import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import {
  addCommentToTask,
  assignTaskToUser,
  createTask,
  deleteTask,
  getTasksByProject,
  updateTask,
  updateTaskStatus,
  uploadTaskFile,
} from "../services/taskService";
import { getProjectById } from "../services/projectService";

function TaskPage() {
  const { id } = useParams(); // ✅ بدل projectId

  const initialFormData = {
    title: "",
    description: "",
    priority: "medium",
    deadline: "",
    projectId: id || "",
    assignedTo: "",
    createdBy: "",
  };

  const [tasks, setTasks] = useState([]);
  const [projectMembers, setProjectMembers] = useState([]);
  const [formData, setFormData] = useState(initialFormData);
  const [editingTaskId, setEditingTaskId] = useState(null);
  const [commentInputs, setCommentInputs] = useState({});
  const [selectedFiles, setSelectedFiles] = useState({});
  const [showForm, setShowForm] = useState(false);

  // 🔹 Fetch tasks
  const fetchTasks = async () => {
    try {
      if (!id) return;
      const data = await getTasksByProject(id);
      setTasks(data);
    } catch (error) {
      console.error("Error fetching tasks:", error.message);
    }
  };

  // 🔹 Fetch members
  const fetchProjectMembers = async () => {
    try {
      if (!id) return;
      const project = await getProjectById(id);
      setProjectMembers(project.members || []);
    } catch (error) {
      console.error("Error fetching project members:", error.message);
    }
  };

  useEffect(() => {
    setFormData((prev) => ({
      ...prev,
      projectId: id || "",
    }));

    fetchTasks();
    fetchProjectMembers();
  }, [id]);

  // 🔹 Get username
  const getUsernameById = (userId) => {
    if (!userId) return "Not assigned";

    if (typeof userId === "object" && userId.username) {
      return userId.username;
    }

    const foundUser = projectMembers.find((m) => m._id === userId);
    return foundUser ? foundUser.username : userId;
  };

  // 🔹 Inputs
  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  // 🔹 Create / Update
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const payload = {
        ...formData,
        projectId: id || "",
      };

      if (editingTaskId) {
        await updateTask(editingTaskId, payload);
        setEditingTaskId(null);
      } else {
        await createTask(payload);
      }

      setFormData({
        ...initialFormData,
        projectId: id || "",
      });

      setShowForm(false);
      fetchTasks();
    } catch (error) {
      console.error("Error saving task:", error.message);
    }
  };

  // 🔹 Delete
  const handleDelete = async (taskId) => {
    await deleteTask(taskId);
    fetchTasks();
  };

  // 🔹 Status
  const handleStatusChange = async (taskId, status) => {
    await updateTaskStatus(taskId, status);
    fetchTasks();
  };

  // 🔹 Assign
  const handleAssignChange = async (taskId, userId) => {
    await assignTaskToUser(taskId, userId);
    fetchTasks();
  };

  // 🔹 Edit
  const handleEdit = (task) => {
    setEditingTaskId(task._id);
    setShowForm(true);

    setFormData({
      title: task.title || "",
      description: task.description || "",
      priority: task.priority || "medium",
      deadline: task.deadline?.slice(0, 10) || "",
      projectId: id || "",
      assignedTo:
        typeof task.assignedTo === "object"
          ? task.assignedTo?._id || ""
          : task.assignedTo || "",
      createdBy: task.createdBy || "",
    });
  };

  const handleCancelEdit = () => {
    setEditingTaskId(null);
    setShowForm(false);
    setFormData({
      ...initialFormData,
      projectId: id || "",
    });
  };

  // 🔹 Comments
  const handleAddComment = async (taskId) => {
    const text = commentInputs[taskId];
    if (!text || !text.trim()) return;

    await addCommentToTask(taskId, {
      text,
      author: "64f333333333333333333333",
    });

    setCommentInputs((prev) => ({
      ...prev,
      [taskId]: "",
    }));

    fetchTasks();
  };

  // 🔹 Files
  const handleFileChange = (taskId, file) => {
    setSelectedFiles((prev) => ({
      ...prev,
      [taskId]: file,
    }));
  };

  const handleFileUpload = async (taskId) => {
    const file = selectedFiles[taskId];
    if (!file) return;

    await uploadTaskFile(taskId, file);

    setSelectedFiles((prev) => ({
      ...prev,
      [taskId]: null,
    }));

    fetchTasks();
  };

  return (
    <div className="task-page">
      <h1>Task Management</h1>

      <button onClick={() => setShowForm(!showForm)}>
        {showForm ? "Close Form" : "Add Task"}
      </button>

      {/* FORM */}
      {showForm && (
        <form onSubmit={handleSubmit}>
          <input
            name="title"
            value={formData.title}
            onChange={handleChange}
            placeholder="Title"
            required
          />

          <textarea
            name="description"
            value={formData.description}
            onChange={handleChange}
          />

          <select
            name="priority"
            value={formData.priority}
            onChange={handleChange}
          >
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
          </select>

          <input
            type="date"
            name="deadline"
            value={formData.deadline}
            onChange={handleChange}
          />

          <select
            name="assignedTo"
            value={formData.assignedTo}
            onChange={handleChange}
          >
            <option value="">Select user</option>
            {projectMembers.map((m) => (
              <option key={m._id} value={m._id}>
                {m.username}
              </option>
            ))}
          </select>

          <button type="submit">
            {editingTaskId ? "Update" : "Create"}
          </button>

          <button type="button" onClick={handleCancelEdit}>
            Cancel
          </button>
        </form>
      )}

      {/* TASKS */}
      {tasks.map((task) => (
        <div key={task._id}>
          <h3>{task.title}</h3>
          <p>{task.description}</p>

          <p>Status: {task.status}</p>
          <p>Assigned: {getUsernameById(task.assignedTo)}</p>

          <select
            value={task.status}
            onChange={(e) =>
              handleStatusChange(task._id, e.target.value)
            }
          >
            <option value="todo">To do</option>
            <option value="inprogress">In progress</option>
            <option value="done">Done</option>
          </select>

          <select
            value={
              typeof task.assignedTo === "object"
                ? task.assignedTo?._id || ""
                : task.assignedTo || ""
            }
            onChange={(e) =>
              handleAssignChange(task._id, e.target.value)
            }
          >
            <option value="">Assign user</option>
            {projectMembers.map((m) => (
              <option key={m._id} value={m._id}>
                {m.username}
              </option>
            ))}
          </select>

          <button onClick={() => handleEdit(task)}>Edit</button>
          <button onClick={() => handleDelete(task._id)}>Delete</button>
        </div>
      ))}
    </div>
  );
}

export default TaskPage;
